		AgentResponseUpdate agentResponseUpdate = null;
		if (AdditionalProperties != null || Usage != null)
		{
			agentResponseUpdate = new AgentResponseUpdate
			{
				AdditionalProperties = AdditionalProperties
			};
			UsageDetails usage = Usage;
			if (usage != null)
			{
				agentResponseUpdate.Contents.Add((AIContent)new UsageContent(usage));
			}
		}
		int num = _messages?.Count ?? 0;
		AgentResponseUpdate[] array = new AgentResponseUpdate[num + ((agentResponseUpdate != null) ? 1 : 0)];
		int i;
