			{
				AdditionalProperties = val.AdditionalProperties,
				AuthorName = val.AuthorName,
				Contents = val.Contents,
				RawRepresentation = val.RawRepresentation,
				Role = val.Role,
				FinishReason = FinishReason,
				AgentId = AgentId,
