using System.ComponentModel;
using System.Net.Http.Json;
using System.Text;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration -----------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Tools -------------------------------------------------------------------

var notebook = new ResearchNotebook();

var searchTool = AIFunctionFactory.Create(
    SearchWebAsync,
    "search_web",
    "Searches the web for a query and returns a list of result snippets. " +
    "Use this to find information about a research topic.");

var addNoteTool = AIFunctionFactory.Create(
    notebook.AddNote,
    "add_note",
    "Saves a research note with a title and body. " +
    "Use this to record key findings during research.");

var readNotesTool = AIFunctionFactory.Create(
    notebook.ReadNotes,
    "read_notes",
    "Returns all previously saved research notes. " +
    "Use this to review what has been recorded so far.");

// --- Agent setup -------------------------------------------------------------

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant. When the user gives you a topic:
        1. Search the web 2-3 times with varied queries to gather diverse information.
        2. Save the most important findings as notes using the add_note tool.
        3. After gathering enough information, read your notes with read_notes.
        4. Provide a well-structured summary that synthesizes your research.
        Be thorough but concise. Cite sources when possible.
        """,
    name: "ResearchAgent",
    description: "An AI agent that researches topics by searching the web and taking notes.",
    tools: [searchTool, addNoteTool, readNotesTool]);

// --- Main loop ---------------------------------------------------------------

Console.WriteLine("╔══════════════════════════════════════════════╗");
Console.WriteLine("║         AI Research Agent                    ║");
Console.WriteLine("║  Enter a topic to research, or 'quit' to    ║");
Console.WriteLine("║  exit.                                       ║");
Console.WriteLine("╚══════════════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic))
        continue;
    if (topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notebook.Clear();
    Console.WriteLine();
    Console.ForegroundColor = ConsoleColor.Yellow;
    Console.WriteLine($"🔍 Researching: {topic}");
    Console.ResetColor();
    Console.WriteLine();

    try
    {
        var response = await agent.RunAsync(
            $"Research the following topic and provide a comprehensive summary: {topic}",
            session: null,
            options: new ChatClientAgentRunOptions(new ChatOptions
            {
                Temperature = 0.2f,
                MaxOutputTokens = 2048,
            }));

        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine("━━━ Research Summary ━━━━━━━━━━━━━━━━━━━━━━━━━");
        Console.ResetColor();
        Console.WriteLine(response.Text);
        Console.WriteLine("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");

        if (notebook.Count > 0)
        {
            Console.ForegroundColor = ConsoleColor.DarkGray;
            Console.WriteLine($"\n📝 {notebook.Count} note(s) saved during research.");
            Console.ResetColor();
        }
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.Error.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
    }

    Console.WriteLine();
}

Console.WriteLine("Goodbye!");
return;

// --- Tool implementations ----------------------------------------------------

[Description("Searches the web for a query and returns result snippets.")]
static async Task<string> SearchWebAsync(
    [Description("The search query string")] string query,
    CancellationToken cancellationToken = default)
{
    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd(
        "ResearchAgent/1.0 (compatible; research bot)");

    try
    {
        // Use DuckDuckGo Instant Answer API (no API key required)
        var encodedQuery = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encodedQuery}&format=json&no_html=1&skip_disambig=1";

        var json = await http.GetFromJsonAsync<JsonElement>(url, cancellationToken);

        var results = new StringBuilder();
        results.AppendLine($"Search results for: \"{query}\"");
        results.AppendLine();

        // Abstract (main answer)
        var abstractText = json.GetProperty("AbstractText").GetString();
        var abstractSource = json.GetProperty("AbstractSource").GetString();
        var abstractUrl = json.GetProperty("AbstractURL").GetString();
        if (!string.IsNullOrWhiteSpace(abstractText))
        {
            results.AppendLine($"## {abstractSource}");
            results.AppendLine(abstractText);
            results.AppendLine($"Source: {abstractUrl}");
            results.AppendLine();
        }

        // Related topics
        if (json.TryGetProperty("RelatedTopics", out var relatedTopics))
        {
            var count = 0;
            foreach (var topic in relatedTopics.EnumerateArray())
            {
                if (count >= 5) break;
                var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                var firstUrl = topic.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;
                if (!string.IsNullOrWhiteSpace(text))
                {
                    results.AppendLine($"- {text}");
                    if (!string.IsNullOrWhiteSpace(firstUrl))
                        results.AppendLine($"  URL: {firstUrl}");
                    count++;
                }
            }
        }

        // Answer field
        var answer = json.GetProperty("Answer").GetString();
        if (!string.IsNullOrWhiteSpace(answer))
        {
            results.AppendLine();
            results.AppendLine($"Direct answer: {answer}");
        }

        var result = results.ToString();
        return string.IsNullOrWhiteSpace(result.Trim())
            ? $"No detailed results found for \"{query}\". Try a different search query."
            : result;
    }
    catch (Exception ex)
    {
        return $"Search failed for \"{query}\": {ex.Message}. Try a different query.";
    }
}

// --- Notebook ----------------------------------------------------------------

sealed class ResearchNotebook
{
    private readonly List<(string Title, string Body)> _notes = [];

    public int Count => _notes.Count;

    [Description("Saves a research note with a title and body.")]
    public string AddNote(
        [Description("Short title for the note")] string title,
        [Description("Detailed content of the note")] string body)
    {
        _notes.Add((title, body));
        return $"Note saved: \"{title}\" ({_notes.Count} total notes)";
    }

    [Description("Returns all saved research notes.")]
    public string ReadNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notes ({_notes.Count}) ===");
        for (var i = 0; i < _notes.Count; i++)
        {
            var (title, body) = _notes[i];
            sb.AppendLine($"\n--- Note {i + 1}: {title} ---");
            sb.AppendLine(body);
        }
        return sb.ToString();
    }

    public void Clear() => _notes.Clear();
}

