     "Use this to review what has been recorded so far.");

 // --- Agent setup -------------------------------------------------------------

 IChatClient chatClient = new OpenAIClient(apiKey)
     .GetChatClient(modelId)
     .AsIChatClient();

 var agent = new ChatClientAgent(
     chatClient,
     instructions: """
         You are a research assistant. When the user gives you a topic:
         1. Search the web 2-3 times with varied queries to gather diverse information.
         2. Save the most important findings as notes using the add_note tool.
         3. After gathering enough information, read your notes with read_notes.
         4. Provide a well-structured summary that synthesizes your research.
         Be thorough but concise. Cite sources when possible.
         """,
     name: "ResearchAgent",
     description: "An AI agent that researches topics by searching the web and taking notes.",
     tools: [searchTool, addNoteTool, readNotesTool]);

 // --- Main loop ---------------------------------------------------------------

